-- KB: loop / cycle flows are not supported (EN + VI)
-- Added after AI support incorrectly told a user that loops were possible.

INSERT INTO knowledge_base (title, slug, content_markdown, category, is_active) VALUES

(
  'Can I Create a Loop in a Workflow?',
  'flow-loop-not-supported',
  E'# Can I Create a Loop in a Workflow?\n\n**No. Aitomic Flow does not support looping or cyclic flows.**\n\nA loop means routing a step''s output back to an earlier step — for example, Step C → Step A — so the same steps repeat until a condition is met. This pattern is explicitly blocked and cannot be built.\n\n## Why loops are not supported\n\n**In the Flow Builder canvas**\n\nWhen you draw a connection, Aitomic Flow runs a cycle-detection check before accepting it. Starting from the target node, it walks all forward paths. If it can reach the source node, the connection is rejected and the wire snaps back. You cannot complete a connection that would form a cycle — not to an earlier Action step, not to the Trigger node, not to any previously visited node.\n\n**In the workflow engine**\n\nThe runtime follows `graph.edges` from each completed step to find the next step. It has no concept of an iteration count, a "visited" set, or a loop limit. If a cycle were somehow present in the stored graph, the engine would attempt to create step instances indefinitely until it timed out.\n\n**In the data model**\n\nFlow instances track a single `current_step_id`. Step instances are append-only rows — there is no iteration-aware reset for SLA deadlines, escalation timers, or assignee resolution.\n\n## What to do instead\n\nMost "loop until approved" use-cases fit one of these three patterns:\n\n### 1. Rejection → Revise → Re-submit (recommended)\n\nModel the loop explicitly as a linear path with a revision step:\n\n```\nTrigger\n  → Submit request         (requester)\n  → Manager review         (branch: Approve / Reject)\n  → [Yes] Finance process  → Complete\n  → [No]  Revise request   (requester)\n        → Second review    (branch: Approve / Reject)\n        → [Yes] Finance process  → Complete\n        → [No]  Complete (rejected)\n```\n\nThis supports up to N explicit revision rounds. Each round is a distinct set of step instances, visible in the instance history. SLA deadlines reset per step.\n\n### 2. Re-trigger a new flow instance\n\nWhen a request is rejected, the requester simply triggers the flow again from scratch. The new instance has a clean history. This is the simplest pattern and works well for short approval flows.\n\n### 3. Multi-round review in a single flow\n\nAdd Round 2, Round 3 action steps explicitly to the canvas. The flow is longer but has a guaranteed end, clear history per round, and no cycle risk.\n\n## Summary\n\n| What you want | What to do |\n|---|---|\n| Retry until approved (up to 2–3 rounds) | Add explicit revision steps for each round |\n| Unlimited retries | Re-trigger a new flow instance on each rejection |\n| Approval with back-and-forth comments | Use the flow''s **comment thread** for discussion; keep the approval step linear |\n\n## See also\n\n- [Understanding the Four Step Types](/help/understanding-step-types)\n- [How Branch Conditions Work](/help/how-branch-conditions-work)\n- [How to Create a Workflow](/help/how-to-create-workflow)',
  'technical',
  true
),

(
  'Quy trình vòng lặp có được hỗ trợ không?',
  'flow-loop-not-supported-vi',
  E'# Quy trình vòng lặp có được hỗ trợ không?\n\n**Không. Aitomic Flow không hỗ trợ quy trình vòng lặp hoặc chu trình.**\n\nVòng lặp có nghĩa là định tuyến đầu ra của một bước quay lại bước trước đó — ví dụ: Bước C → Bước A — để các bước lặp lại cho đến khi điều kiện được đáp ứng. Mẫu này bị chặn tường minh và không thể xây dựng được.\n\n## Tại sao vòng lặp không được hỗ trợ\n\n**Trong canvas Flow Builder**\n\nKhi bạn vẽ một kết nối, Aitomic Flow chạy kiểm tra phát hiện chu trình trước khi chấp nhận. Bắt đầu từ nút đích, nó duyệt tất cả các đường đi phía trước. Nếu nó có thể đến nút nguồn, kết nối bị từ chối và đường dây bật lại. Bạn không thể hoàn thành kết nối tạo thành chu trình — không đến bước Action trước đó, không đến nút Trigger, không đến bất kỳ nút nào đã được truy cập.\n\n**Trong công cụ thực thi quy trình**\n\nEngine theo dõi `graph.edges` từ mỗi bước đã hoàn thành để tìm bước tiếp theo. Nó không có khái niệm về số lần lặp, tập hợp "đã thăm", hoặc giới hạn vòng lặp. Nếu chu trình bằng cách nào đó hiện diện trong đồ thị đã lưu, engine sẽ cố gắng tạo step_instances vô thời hạn cho đến khi hết thời gian.\n\n## Thay thế bằng cách nào\n\nHầu hết các trường hợp "lặp cho đến khi được phê duyệt" phù hợp với một trong ba mẫu này:\n\n### 1. Từ chối → Chỉnh sửa → Gửi lại (khuyến nghị)\n\nMô hình hóa vòng lặp một cách tường minh dưới dạng đường tuyến tính có bước chỉnh sửa:\n\n```\nTrigger\n  → Gửi yêu cầu         (người yêu cầu)\n  → Xem xét của quản lý  (nhánh: Phê duyệt / Từ chối)\n  → [Có] Xử lý tài chính  → Hoàn thành\n  → [Không] Chỉnh sửa yêu cầu  (người yêu cầu)\n         → Xem xét lần 2  (nhánh: Phê duyệt / Từ chối)\n         → [Có] Xử lý tài chính  → Hoàn thành\n         → [Không] Hoàn thành (bị từ chối)\n```\n\nMẫu này hỗ trợ tối đa N vòng chỉnh sửa tường minh. Mỗi vòng là một tập hợp step_instance riêng biệt, hiển thị trong lịch sử phiên bản.\n\n### 2. Kích hoạt lại phiên bản mới\n\nKhi yêu cầu bị từ chối, người yêu cầu đơn giản kích hoạt lại quy trình từ đầu. Phiên bản mới có lịch sử sạch. Đây là mẫu đơn giản nhất.\n\n### 3. Xem xét nhiều vòng trong một quy trình\n\nThêm rõ ràng các bước Vòng 2, Vòng 3 vào canvas. Quy trình dài hơn nhưng có điểm kết thúc được đảm bảo và lịch sử rõ ràng theo từng vòng.\n\n## Tóm tắt\n\n| Bạn muốn gì | Nên làm gì |\n|---|---|\n| Thử lại cho đến khi được phê duyệt (2–3 vòng) | Thêm bước chỉnh sửa tường minh cho mỗi vòng |\n| Thử lại không giới hạn | Kích hoạt lại phiên bản quy trình mới khi bị từ chối |\n| Phê duyệt với thảo luận qua lại | Dùng **luồng bình luận** của quy trình; giữ bước phê duyệt tuyến tính |\n\n## Xem thêm\n\n- [Tìm hiểu bốn loại bước trong quy trình](/help/understanding-step-types-vi)\n- [Cách hoạt động của điều kiện rẽ nhánh](/help/how-branch-conditions-work-vi)\n- [Cách tạo quy trình làm việc](/help/how-to-create-workflow-vi)',
  'technical',
  true
)

ON CONFLICT (slug) DO NOTHING;
